typescript_interfaces:
// TypeScript interfaces for Lovable import
export interface DiscoveryMeta {
  version: string;
  generated: string;
  total_clips: number;
  total_shots: number;
  hypothesis_verdict: 'SUPPORTED' | 'SUPPORTED_WITH_CAVEATS' | 'INCONCLUSIVE' | 'REFUTED';
}

export interface Discovery {
  id: string;
  rank: number;
  composite_score: number;
  title: string;
  category: 'shot_sequence_signature' | 'error_pattern' | 'rally_length' | 'skill_signature';
  finding: string;
  data_points: number;
  confidence_score: number; // 0-100, capped per validation rules
  why_it_matters: string;
  sampling_bias_flag: string;
  strongest_counter_argument: string;
  hypothesis_score: number; // 0-100
  metrics: Record<string, unknown>;
}

export interface CorpusStats {
  shot_type_counts: Record<string, number>;
  speedup_outcomes: {
    winner: number; error: number; rally_continues: number;
    winner_rate: number; error_rate: number;
  };
  kitchen_mastery_by_dupr: Record<string, number>;
  avg_rally_length_by_dupr: Record<string, number>;
}
